use std::path::Path;

/// TOML template written by `xray init`.
const TEMPLATE: &str = r#"# xray.toml — HPC scientific Python linter configuration
# Generated by `xray init`.  Uncomment and adjust as needed.
# Run `xray --list-rules` to see all available rule IDs.
# Run `xray explain <RULE_ID>` for rationale and examples.

# ── Global rule control ────────────────────────────────────────────────────────
# Disable specific rules for the entire project.  Rule IDs are case-sensitive.
# disable = ["NP003", "IO001"]


# ── Per-rule severity overrides ────────────────────────────────────────────────
# Override the default severity for individual rules.
# Valid values: "hint" | "warning" | "error"
# Example: promote XR002 to error for strict codebases, demote NP003 to hint.
# [severity_overrides]
# XR002 = "error"
# NP003 = "hint"


# ── Path control ───────────────────────────────────────────────────────────────
# Control which files are linted when you run bare `xray` with no path arguments.
# [paths]
# Files to include (glob patterns).  Default: all .py files recursively.
# include = ["**/*.py"]
#
# Files to exclude (glob patterns).  Applied after include.
# exclude = ["tests/fixtures/**", "**/vendor/**", "**/generated_*.py"]


# ── xarray rules ──────────────────────────────────────────────────────────────
[xarray]
# Treat .values access (XR002) as an error rather than a warning.
# Upgrade this if your codebase treats coordinate metadata as safety-critical.
# values_access_is_error = false


# ── dask rules ────────────────────────────────────────────────────────────────
[dask]
# Number of .compute() calls in a single file that triggers DK003.
# Lower this if your codebase should always batch computes.
# compute_call_threshold = 3


# ── numpy / pandas rules ──────────────────────────────────────────────────────
[numpy]
# Flag DataFrame.iterrows() calls (NP001).
# Disable if your project intentionally uses iterrows for small DataFrames.
# flag_iterrows = true


# ── I/O rules ─────────────────────────────────────────────────────────────────
[io]
# Flag np.save and netCDF4.Dataset direct-open patterns (IO001, IO002).
# flag_missing_compression = true
"#;

/// Write `xray.toml` in the current directory.
/// Returns an error string on failure.
pub fn init(force: bool) -> Result<(), String> {
    let dest = Path::new("xray.toml");
    if dest.exists() && !force {
        return Err("xray.toml already exists.  Pass --force to overwrite.".to_string());
    }
    std::fs::write(dest, TEMPLATE).map_err(|e| format!("xray: could not write xray.toml: {e}"))?;
    println!("xray: wrote xray.toml");
    println!("  Edit it to customise rules, then run `xray` to lint your project.");
    println!("  Tip: create a .xrayignore file to exclude files or directories.");
    Ok(())
}
